import React, { useEffect, useState } from "react";
import { LineChart, Line, XAxis, YAxis, Tooltip, Legend, ResponsiveContainer } from "recharts";
import { fetchBuses } from "./api";

export default function BusCharts({ show }) {
  const [chartData, setChartData] = useState([]);

  const getChartData = async () => {
    const data = await fetchBuses();
    if (data) {
      // Aggregate per minute for trends
      const ghostCount = data.buses.filter(b => b.isGhost).length;
      const normalCount = data.buses.filter(b => !b.isGhost).length;
      setChartData(prev => [...prev, { time: new Date().toLocaleTimeString(), Ghost: ghostCount, Normal: normalCount }]);
    }
  };

  useEffect(() => {
    getChartData();
    const interval = setInterval(getChartData, 120000); // 2 min
    return () => clearInterval(interval);
  }, []);

  if (!show) return null;

  return (
    <div style={{ width: "400px", height: "300px", backgroundColor: "white", padding: "10px", position: "absolute", bottom: 10, right: 10, zIndex: 1000 }}>
      <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData}>
          <XAxis dataKey="time" />
          <YAxis />
          <Tooltip />
          <Legend />
          <Line type="monotone" dataKey="Ghost" stroke="red" />
          <Line type="monotone" dataKey="Normal" stroke="green" />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}
